+                body_stmt,
+                ops,
+                bindings,
+                binding_lookup,
+                binding_index,
+                scope_id,
+                label_counter,
+                switch_flow,
+            )?;
+        }
+    }
+
+    ops.push(Ir1Op::Label { id: end_label });
